-- Payload Launcher (minimal / clean)

local sc = ""

init_dlsym()
sceMsgDialogTerminate()

sc = sc:gsub("%s", "")
local JIT_SIZE = 0x80000

local bfd = jit_malloc(8)
local rwfd = jit_malloc(8)
local rxfd = jit_malloc(8)
local rwa = jit_malloc(8)
local rxa = malloc(8)
local nm = jit_malloc(8)

jit_write_buffer(nm, "nv4b")
jit_sceKernelJitCreateSharedMemory(nm, JIT_SIZE, 7, bfd)
jit_sceKernelJitCreateAliasOfSharedMemory(jit_read32(bfd), PROT_READ | PROT_WRITE, rwfd)
jit_sceKernelJitCreateAliasOfSharedMemory(jit_read32(bfd), PROT_READ | PROT_EXECUTE, rxfd)
jit_sceKernelJitMapSharedMemory(jit_read32(rwfd), PROT_READ | PROT_WRITE, rwa)

local rw = jit_read64(rwa)
local mfd = jit_send_recv_fd(jit_read32(rxfd), NEW_JIT_SOCK, NEW_MAIN_SOCK)
sceKernelJitMapSharedMemory(mfd, PROT_READ | PROT_EXECUTE, rxa)
local rx = read64(rxa)
local bfd_fd = jit_read32(bfd)
local rwfd_fd = jit_read32(rwfd)
local rxfd_fd = jit_read32(rxfd)

write_shellcode(rw, sc)

-- Keep ext_args available for payloads that expect it, but with neutral values.
local ext = malloc(0x80)
memset(ext, 0, 0x80)
write64(ext + 0x00, 0xDEAD)
write32(ext + 0x18, -1)
write32(ext + 0x1C, -1)

-- Resolve userId like the full launcher so examples using ex->user_id are stable.
local userId = 0
if not sceKernelLoadStartModule then
    sceKernelLoadStartModule = func_wrap(dlsym(LIBKERNEL_HANDLE, "sceKernelLoadStartModule"))
end
if sceKernelLoadStartModule then
    local libUser = sceKernelLoadStartModule("libSceUserService.sprx", 0, 0, 0, 0, 0)
    if libUser and libUser > 0 then
        local getUserId = dlsym(libUser, "sceUserServiceGetInitialUser")
        if getUserId then
            local uid_buf = malloc(4)
            write32(uid_buf, 0)
            pcall(function() func_wrap(getUserId)(uid_buf) end)
            userId = read32(uid_buf)
        end
    end
end
write64(ext + 0x48, userId)

func_wrap(rx)(EBOOT_BASE, SCE_KERNEL_DLSYM, ext)

-- Best-effort: return to PS5 main UI after payload finishes.
local function return_to_ps5_menu()
    local ok = pcall(function()
        if not sceKernelLoadStartModule then
            sceKernelLoadStartModule = func_wrap(dlsym(LIBKERNEL_HANDLE, "sceKernelLoadStartModule"))
        end
        if not sceKernelLoadStartModule then return end
        local hsys = sceKernelLoadStartModule("libSceSystemService.sprx", 0, 0, 0, 0, 0)
        if not hsys or hsys <= 0 then return end
        local get_app_status = dlsym(hsys, "sceSystemServiceGetAppStatus")
        local kill_app = dlsym(hsys, "sceSystemServiceKillApp")
        local usleep_fn = dlsym(LIBKERNEL_HANDLE, "sceKernelUsleep")
        if not get_app_status or not kill_app then return end
        local st = malloc(0x100)
        memset(st, 0, 0x100)
        local gr = func_wrap(get_app_status)(st)
        if gr ~= 0 then return end
        local sent = false
        for off = 0, 0x3C, 4 do
            local app_id = read32(st + off)
            if app_id ~= 0 and app_id ~= 0xFFFFFFFF and app_id >= 0x10 and app_id <= 0x7FFFFFFF then
                local kr = func_wrap(kill_app)(app_id)
                if kr == 0 then sent = true end
            end
        end
        if sent and usleep_fn then
            func_wrap(usleep_fn)(500000)
        end
    end)
    return ok
end
return_to_ps5_menu()

-- JIT FD cleanup to keep repeated launches stable.
if mfd and mfd >= 0 then pcall(function() syscall.close(mfd) end) end
if rxfd_fd and rxfd_fd >= 0 then pcall(function() syscall.close(rxfd_fd) end) end
if rwfd_fd and rwfd_fd >= 0 then pcall(function() syscall.close(rwfd_fd) end) end
if bfd_fd and bfd_fd >= 0 then pcall(function() syscall.close(bfd_fd) end) end
